-- Seed static menu data into UUID-based Supabase catalog tables.
-- Safe to rerun: uses ON CONFLICT (id) DO UPDATE upserts.
-- Upserts categories/products from static menu into UUID id columns.
-- This script does not delete old duplicate/test rows already in the database.

BEGIN;

ON CONFLICT (id) DO UPDATE
SET
  name = EXCLUDED.name,
  display_order = EXCLUDED.display_order;

ON CONFLICT (id) DO UPDATE
SET
  name = EXCLUDED.name,
  price = EXCLUDED.price,
  description = EXCLUDED.description,
  category_id = EXCLUDED.category_id,
  display_order = EXCLUDED.display_order,
  is_active = EXCLUDED.is_active;

COMMIT;
